1	/**
2	 * Ingest delivery workflow
3	 *
4	 * Replaces the relay Upstash Workflow (5 steps) + QStash dispatch +
5	 * console ingress Upstash Workflow (2 steps) with a single Inngest function.
6	 *
7	 * Steps:
8	 * 1. resolve-connection — query orgIntegrations, or use preResolved
9	 * 2. transform-and-store — call transformEnvelope, insert ingest log
10	 * 3. emit-event-capture — step.sendEvent("platform/event.capture")
11	 * 4. publish-realtime — Upstash Realtime SSE for console UI
12	 */
13	
14	import { db } from "@db/app/client";
15	import {
16	  gatewayWebhookDeliveries,
17	  orgIngestLogs,
18	  orgIntegrations,
19	} from "@db/app/schema";
20	import type { ProviderSlug } from "@repo/app-providers";
21	import { sanitizePostTransformEvent } from "@repo/app-providers";
22	import type { EventNotification } from "@repo/app-upstash-realtime";
23	import { realtime } from "@repo/app-upstash-realtime";
24	import { NonRetriableError } from "@vendor/inngest";
25	import { log } from "@vendor/observability/log/next";
26	import { and, eq } from "drizzle-orm";
27	import { transformEnvelope } from "../../lib/transform";
28	import { inngest } from "../client";
29	
30	export const ingestDelivery = inngest.createFunction(
31	  {
32	    id: "platform/ingest.delivery",
33	    name: "Ingest Delivery",
34	    description:
35	      "Webhook delivery -> transform -> emit event.capture (replaces relay workflow + QStash + console ingress)",
36	    concurrency: {
37	      limit: 20,
38	      key: "event.data.provider",
39	    },
40	    retries: 3,
41	    timeouts: {
42	      start: "1m",
43	      finish: "3m",
44	    },
45	  },
46	  { event: "platform/webhook.received" },
47	  async ({ event, step }) => {
48	    const data = event.data;
49	
50	    // Step 1: Resolve connection from resource ID or use preResolved
51	    const connectionInfo = await step.run("resolve-connection", async () => {
52	      if (data.preResolved) {
53	        return data.preResolved;
54	      }
55	
56	      if (!data.resourceId) {
57	        return null;
58	      }
59	
60	      const rows = await db
61	        .select({
62	          installationId: orgIntegrations.installationId,
63	          orgId: orgIntegrations.clerkOrgId,
64	        })
65	        .from(orgIntegrations)
66	        .where(
67	          and(
68	            eq(orgIntegrations.providerResourceId, data.resourceId),
69	            eq(orgIntegrations.status, "active")
70	          )
71	        )
72	        .limit(1);
73	
74	      const row = rows[0];
75	      if (!row) {
76	        return null;
77	      }
78	
79	      return { connectionId: row.installationId, orgId: row.orgId };
80	    });
81	
82	    if (!connectionInfo?.orgId) {
83	      throw new NonRetriableError("no_connection");
84	    }
85	
86	    // clerkOrgId IS the orgId
87	    const clerkOrgId = connectionInfo.orgId;
88	
89	    log.info("connection resolved", {
90	      deliveryId: data.deliveryId,
91	    });
92	
93	    // Step 2: Transform envelope and store ingest log
94	    const result = await step.run("transform-and-store", async () => {
95	      const rawEvent = transformEnvelope({
96	        provider: data.provider as ProviderSlug,
97	        eventType: data.eventType,
98	        payload: data.payload,
99	        deliveryId: data.deliveryId,
100	        receivedAt: data.receivedAt,
101	        orgId: connectionInfo.orgId,
102	        connectionId: connectionInfo.connectionId,
103	      });
104	
105	      if (!rawEvent) {
106	        log.info("no transformer, skipping", {
107	          eventType: data.eventType,
108	          deliveryId: data.deliveryId,
109	        });
110	        return { status: "unsupported" as const };
111	      }
112	
113	      const sourceEvent = sanitizePostTransformEvent(rawEvent);
114	
115	      const [record] = await db
116	        .insert(orgIngestLogs)
117	        .values({
118	          clerkOrgId,
119	          deliveryId: data.deliveryId,
120	          sourceEvent,
121	          receivedAt: new Date(data.receivedAt).toISOString(),
122	          ingestionSource: "webhook",
123	        })
124	        .returning({ id: orgIngestLogs.id });
125	
126	      if (!record) {
127	        throw new Error("Failed to insert ingest log");
128	      }
129	
130	      return {
131	        status: "transformed" as const,
132	        sourceEvent,
133	        ingestLogId: record.id,
134	      };
135	    });
136	
137	    // Unsupported event type — return early, no downstream events
138	    if (result.status === "unsupported") {
139	      await step.run("mark-delivery-skipped", async () => {
140	        await db
141	          .update(gatewayWebhookDeliveries)
142	          .set({ status: "skipped" })
143	          .where(eq(gatewayWebhookDeliveries.deliveryId, data.deliveryId));
144	      });
145	      return {
146	        status: "unsupported",
147	        provider: data.provider,
148	        eventType: data.eventType,
149	      };
150	    }
151	
152	    // Step 3: Emit platform/event.capture to trigger the neural pipeline
153	    await step.sendEvent("emit-event-capture", {
154	      name: "platform/event.capture" as const,
155	      data: {
156	        clerkOrgId,
157	        sourceEvent: result.sourceEvent,
158	        ingestionSource: "webhook",
159	        ingestLogId: result.ingestLogId,
160	        correlationId: data.correlationId,
161	      },
162	    });
163	
164	    // Step 4: Publish to Upstash Realtime for console SSE
165	    await step.run("publish-realtime", async () => {
166	      const channel = realtime.channel(`org-${clerkOrgId}`);
167	      await channel.emit("org.event", {
168	        eventId: result.ingestLogId,
169	        clerkOrgId,
170	        sourceEvent: result.sourceEvent,
171	      } satisfies EventNotification);
172	    });
173	
174	    // Step 5: Mark delivery as processed
175	    await step.run("mark-delivery-processed", async () => {
176	      await db
177	        .update(gatewayWebhookDeliveries)
178	        .set({ status: "processed" })
179	        .where(eq(gatewayWebhookDeliveries.deliveryId, data.deliveryId));
